+use std::sync::Arc;
+
+use fcp_core::{BaseConnector, ConnectorId, FcpError, FcpResult};
+use serde_json::{Value, json};
+
+const CONNECTOR_ID: &str = "fcp.elevenlabs";
+const CONNECTOR_VERSION: &str = "0.1.0";
+const BOUNDARY: &str = "This first slice focuses on text-to-speech generation and voice discovery.";
+
+pub struct ElevenlabsConnector {
+    base: Arc<BaseConnector>,
+    configured: bool,
+    handshaken: bool,
+}
+
+impl ElevenlabsConnector {
+    #[must_use]
+    pub fn new() -> Self {
+        Self {
+            base: Arc::new(BaseConnector::new(ConnectorId::from_static(CONNECTOR_ID))),
+            configured: false,
+            handshaken: false,
+        }
+    }
+
+    pub async fn handle_configure(&mut self, _params: Value) -> FcpResult<Value> {
+        self.configured = true;
+        self.base.set_configured(true);
+        Ok(json!({"connector_id": CONNECTOR_ID, "configured": true}))
+    }
+
+    pub async fn handle_handshake(&mut self, _params: Value) -> FcpResult<Value> {
+        if !self.configured {
+            return Err(FcpError::NotConfigured);
+        }
+        self.handshaken = true;
+        self.base.set_handshaken(true);
+        Ok(json!({
+            "connector_id": CONNECTOR_ID,
+            "connector_version": CONNECTOR_VERSION,
+            "protocol_version": "2.0",
+            "capabilities": ["elevenlabs.tts", "elevenlabs.voices"]
+        }))
+    }
+
+    pub async fn handle_health(&self) -> FcpResult<Value> {
+        Ok(json!({
+            "status": if self.configured && self.handshaken { "healthy" } else if self.configured { "degraded" } else { "unconfigured" },
+            "configured": self.configured,
+            "handshaken": self.handshaken,
+        }))
+    }
+
+    pub async fn handle_doctor(&self) -> FcpResult<Value> {
+        Ok(json!({
+            "status": if self.configured { "healthy" } else { "unhealthy" },
+            "checks": [
+                { "name": "configuration", "passed": self.configured, "critical": true },
+                { "name": "handshake", "passed": self.handshaken, "critical": false },
+                { "name": "surface_boundary", "passed": true, "critical": false, "message": BOUNDARY }
+            ]
+        }))
+    }
+
+    pub async fn handle_self_check(&self) -> FcpResult<Value> {
+        Ok(json!({
+            "status": if self.configured { "ok" } else { "degraded" },
+            "reason_code": if self.configured { Value::Null } else { json!("not_configured") },
+            "message": BOUNDARY
+        }))
+    }
+
+    pub async fn handle_introspect(&self) -> FcpResult<Value> {
+        Ok(json!({
+            "connector_id": CONNECTOR_ID,
+            "version": CONNECTOR_VERSION,
+            "operations": [
+                { "id": "elevenlabs.tts.generate", "summary": "Generate ElevenLabs speech audio", "capability": "elevenlabs.tts", "risk_level": "medium", "safety_tier": "safe", "idempotency": "strict" },
+                { "id": "elevenlabs.voices.list", "summary": "List ElevenLabs voices", "capability": "elevenlabs.voices", "risk_level": "low", "safety_tier": "safe", "idempotency": "strict" }
+            ],
+            "events": [],
+            "resource_types": []
+        }))
+    }
+
+    pub async fn handle_invoke(&self, params: Value) -> FcpResult<Value> {
+        self.base.check_ready()?;
+        let operation = params
+            .get("operation_id")
+            .or_else(|| params.get("operation"))
+            .and_then(Value::as_str)
+            .ok_or_else(|| FcpError::InvalidRequest {
+                code: 1003,
+                message: "Missing operation_id".into(),
+            })?;
+
+        Ok(json!({
+            "status": "not_implemented",
+            "operation_id": operation,
+            "connector_id": CONNECTOR_ID,
+            "boundary": BOUNDARY
+        }))
+    }
+
+    pub async fn handle_simulate(&self, params: Value) -> FcpResult<Value> {
+        let operation = params
+            .get("operation_id")
+            .or_else(|| params.get("operation"))
+            .and_then(Value::as_str)
+            .unwrap_or("");
+
+        Ok(json!({
+            "allowed": matches!(operation, "elevenlabs.tts.generate" | "elevenlabs.voices.list"),
+            "reason": BOUNDARY
+        }))
+    }
+
+    pub async fn handle_shutdown(&mut self, _params: Value) -> FcpResult<Value> {
+        self.configured = false;
+        self.handshaken = false;
+        self.base.set_configured(false);
+        self.base.set_handshaken(false);
+        Ok(json!({}))
+    }
+}
+
+impl Default for ElevenlabsConnector {
+    fn default() -> Self {
+        Self::new()
+    }
+}
+

